import os

# Try to explore the user's home directory mentioned in env vars
home_dirs = ['/home/nekutsy', '/home/nekutsy/neuro-ok-bot', '/home/nekutsy/Agent']

for home_dir in home_dirs:
    print(f"\n=== Exploring {home_dir} ===")
    if os.path.exists(home_dir):
        try:
            contents = os.listdir(home_dir)
            print(f"Contents: {contents[:20]}")  # Limit to first 20 items

            # Try to find interesting files
            for item in contents[:10]:
                item_path = os.path.join(home_dir, item)
                if os.path.isfile(item_path):
                    try:
                        file_size = os.path.getsize(item_path)
                        print(f"  File: {item} ({file_size} bytes)")
                    except:
                        pass
                elif os.path.isdir(item_path):
                    print(f"  Directory: {item}")
        except Exception as e:
            print(f"Error: {e}")
    else:
        print("Directory does not exist or not accessible")
